Hi there,

I want to brainstorm a bit. We are currently working on a great refactor (see git status)

With you I want to focus on the actual theme definition itself like src/themes/terra/black-atom-terra-fall-day-next.ts

Since we are now on a more programmatical level, I am thinking about how we can redo stom stuff like this:

````ts
const primaries: ThemePrimaryColorsNext = {
  // d10: colordx("oklch(0.202 0.05 47.49)"),
  get d10() {
    return this.d20.darken(0.05);
  },
  d20: colordx("oklch(0.301 0.049 48.35)"),
  // d30: colordx("oklch(0.348 0.05 49.42)"),
  get d30() {
    return this.d20.lighten(0.075);
  },
  // d40: colordx("oklch(0.438 0.05 49.73)"),
  get d40() {
    return this.d30.lighten(0.075);
  },

  m10: colordx("oklch(0.483 0.075 48.75)"),
  m20: colordx("oklch(0.569 0.074 49.6)"),
  m30: colordx("oklch(0.655 0.075 48.42)"),
  m40: colordx("oklch(0.742 0.075 49.01)"),

  l10: colordx("oklch(0.825 0.055 60)"),
  get l20() {
    return this.l10.lighten(0.075);
  },
  get l30() {
    return this.l20.lighten(0.075);
  },
  get l40() {
    return this.l30.lighten(0.075);
  },
  // l20: colordx("oklch(0.872 0.048 58.95)"),
  // l30: colordx("oklch(0.914 0.042 61.44)"),
  // l40: colordx("oklch(0.94 0.038 61)"),
};
```

I am think about how we can maybe use functions to generate the colors with some options.

```ts
const primaries = generatePrimaries({
    lows: {
        base: colordx("oklch(0.301 0.049 48.35)")
        spread: 0.075
    }
});
```

I am really not sure whats the best way to do this.
Or maybe the simple `get` approach is the best way.

I still want to to be able to set different hues and colors for the different sections like the mids and highs


Or stuff like this:

const palette = createPaletteNext(primaries, {
    red: colordx("oklch(0.568 0.15 29.52)"),
    get darkRed() {
        return this.red.darken(0.1);
    },

    green: colordx("oklch(0.569 0.061 127.36)"),
    get darkGreen() {
        return this.green.darken(0.1);
    },

    yellow: colordx("oklch(0.656 0.16 54.87)"),
    get darkYellow() {
        return this.yellow.darken(0.1);
    },

    blue: colordx("oklch(0.57 0.061 49.91)"),
    get darkBlue() {
        return this.blue.darken(0.1);
    },

    magenta: colordx("oklch(0.57 0.085 40.86)"),
    get darkMagenta() {
        return this.magenta.darken(0.1);
    },

    cyan: colordx("oklch(0.569 0.06 175)"),
    get darkCyan() {
        return this.cyan.darken(0.1);
    },
});

I want to look for easy improvements WITHOUT making it too complicated (KISS)
````

import type {
    ThemeAccentColorsNext,
    ThemeFeedbackColorsNext,
    ThemeGitColorsNext,
    ThemePrimaryColorsNext,
} from "../../types/theme-next.ts";
import { colordx } from "@colordx";
import { themeKeyMetaMap } from "../../types/themes.ts";
import { createThemeDefinition } from "../../lib/create-theme-definition.ts";

import createPaletteNext from "./create-palette-light-next.ts";
import createSyntaxNext from "./create-syntax-light-next.ts";
import createUiNext from "./create-ui-light-next.ts";

const meta = themeKeyMetaMap["black-atom-terra-fall-day-next"];

const primaries: ThemePrimaryColorsNext = {
    // d10: colordx("oklch(0.202 0.05 47.49)"),
    get d10() {
        return this.d20.darken(0.05);
    },
    d20: colordx("oklch(0.301 0.049 48.35)"),
    // d30: colordx("oklch(0.348 0.05 49.42)"),
    get d30() {
        return this.d20.lighten(0.075);
    },
    // d40: colordx("oklch(0.438 0.05 49.73)"),
    get d40() {
        return this.d30.lighten(0.075);
    },

    m10: colordx("oklch(0.483 0.075 48.75)"),
    m20: colordx("oklch(0.569 0.074 49.6)"),
    m30: colordx("oklch(0.655 0.075 48.42)"),
    m40: colordx("oklch(0.742 0.075 49.01)"),

    l10: colordx("oklch(0.825 0.055 60)"),
    get l20() {
        return this.l10.lighten(0.075);
    },
    get l30() {
        return this.l20.lighten(0.075);
    },
    get l40() {
        return this.l30.lighten(0.075);
    },
    // l20: colordx("oklch(0.872 0.048 58.95)"),
    // l30: colordx("oklch(0.914 0.042 61.44)"),
    // l40: colordx("oklch(0.94 0.038 61)"),
};

const palette = createPaletteNext(primaries, {
    red: colordx("oklch(0.568 0.15 29.52)"),
    get darkRed() {
        return this.red.darken(0.1);
    },

    green: colordx("oklch(0.569 0.061 127.36)"),
    get darkGreen() {
        return this.green.darken(0.1);
    },

    yellow: colordx("oklch(0.656 0.16 54.87)"),
    get darkYellow() {
        return this.yellow.darken(0.1);
    },

    blue: colordx("oklch(0.57 0.061 49.91)"),
    get darkBlue() {
        return this.blue.darken(0.1);
    },

    magenta: colordx("oklch(0.57 0.085 40.86)"),
    get darkMagenta() {
        return this.magenta.darken(0.1);
    },

    cyan: colordx("oklch(0.569 0.06 175)"),
    get darkCyan() {
        return this.cyan.darken(0.1);
    },
});

const accents: ThemeAccentColorsNext = {
    a10: palette.yellow,
    a20: palette.darkYellow,
};

const feedback: ThemeFeedbackColorsNext = {
    negative: colordx("oklch(0.482 0.151 29.67)"),
    success: colordx("oklch(0.569 0.061 127.36)"),
    info: colordx("oklch(0.569 0.06 175)"),
    warning: colordx("oklch(0.656 0.16 54.87)"),
};

const Git: ThemeGitColorsNext = {
    add: colordx("oklch(0.482 0.151 29.67)"),
    delete: colordx("oklch(0.569 0.061 127.36)"),
    modify: colordx("oklch(0.569 0.06 175)"),
};

const ui = createUiNext({
    primaries: primaries,
    feedback: feedback,
    git: Git,
    accents: accents,
});

const syntax = createSyntaxNext({
    accents,
    palette,
