## A) Palette Builder — Auto-derive dark* variants

This is the strongest win. Modify `createPaletteLightNext` so you pass only the 6 light base colors, and it derives the dark variants with a configurable factor.

### Implementation

```ts
// src/themes/terra/create-palette-light-next.ts

import type { ThemePaletteColorsNext, ThemePrimaryColorsNext } from "../../types/theme-next.ts";
import type { Colordx } from "@colordx";

/** The 6 light hue anchors — the "color identity" of the theme. */
type PaletteAnchors = Pick<
    ThemePaletteColorsNext<Colordx>,
    "red" | "green" | "yellow" | "blue" | "magenta" | "cyan"
>;

export default function (
    primaries: ThemePrimaryColorsNext,
    anchors: PaletteAnchors,
    options?: { darkenBy?: number },
): ThemePaletteColorsNext {
    const darkenBy = options?.darkenBy ?? 0.1;

    return {
        ...anchors,

        // Auto-derived dark variants
        darkRed: anchors.red.darken(darkenBy),
        darkGreen: anchors.green.darken(darkenBy),
        darkYellow: anchors.yellow.darken(darkenBy),
        darkBlue: anchors.blue.darken(darkenBy),
        darkMagenta: anchors.magenta.darken(darkenBy),
        darkCyan: anchors.cyan.darken(darkenBy),

        // Derived from primaries
        black: primaries.d40,
        gray: primaries.m10,
        lightGray: primaries.l10,
        white: primaries.l30,
    };
}
```

