## B) Primary Scale Builder — The one I'm more cautious about

### What it would look like

```ts
// src/lib/primary-scale.ts

import type { ThemePrimaryColorsNext } from "../types/theme-next.ts";
import type { Colordx } from "@colordx";

interface PrimaryScaleConfig {
    dark: {
        base: Colordx;      // d20 — the dark anchor
        downSpread: number; // darken factor for d10 (e.g. 0.05)
        upSpread: number;   // lighten factor for d30, d40 (e.g. 0.075)
    };
    mids: [Colordx, Colordx, Colordx, Colordx];
    light: {
        base: Colordx;      // l10 — the light anchor
        spread: number;     // lighten factor for l20, l30, l40 (e.g. 0.075)
    };
}

export function primaryScale(config: PrimaryScaleConfig): ThemePrimaryColorsNext {
    return {
        d10: config.dark.base.darken(config.dark.downSpread),
        d20: config.dark.base,
        d30: config.dark.base.lighten(config.dark.upSpread),
        d40: config.dark.base.lighten(config.dark.upSpread)
            .lighten(config.dark.upSpread),
        m10: config.mids[0],
        m20: config.mids[1],
        m30: config.mids[2],
        m40: config.mids[3],
        l10: config.light.base,
        l20: config.light.base.lighten(config.light.spread),
        l30: config.light.base.lighten(config.light.spread)
            .lighten(config.light.spread),
        l40: config.light.base.lighten(config.light.spread)
            .lighten(config.light.spread)
            .lighten(config.light.spread),
    };
}
```

Wait — that d40 / l20-l40 chaining is wrong. The getters in the original are *chained* (d30.lighten(0.075)), not *compounded* (d20.lighten(0.15)). Let me fix that to match the exact behavior:

```ts
export function primaryScale(config: PrimaryScaleConfig): ThemePrimaryColorsNext {
    // Must use getters to match the chained lighten/darken behavior
    return {
        get d10() { return this.d20.darken(config.dark.downSpread) },
        d20: config.dark.base,
        get d30() { return this.d20.lighten(config.dark.upSpread) },
        get d40() { return this.d30.lighten(config.dark.upSpread) },

        m10: config.mids[0],
        m20: config.mids[1],
        m30: config.mids[2],
        m40: config.mids[3],

        l10: config.light.base,
        get l20() { return this.l10.lighten(config.light.spread) },
        get l30() { return this.l20.lighten(config.light.spread) },
        get l40() { return this.l30.lighten(config.light.spread) },
    };
}
```

