## B2) The Lightest Touch Alternative

Instead of a builder function, just expose the spread as a collection constant and keep the getters. This makes the *reasoning* behind the numbers visible without hiding anything:

```ts
// src/themes/terra/shared.ts
export const TERRA = {
    PRIMARY_SPREAD: 0.075,
    DARK_DEEP_SPREAD: 0.05,   // d10 uses tighter spread intentionally
    PALETTE_DARKEN: 0.1,
} as const;

// black-atom-terra-fall-day-next.ts
import { TERRA } from "./shared.ts";

const primaries: ThemePrimaryColorsNext = {
    get d10() { return this.d20.darken(TERRA.DARK_DEEP_SPREAD); },
    d20: colordx("oklch(0.301 0.049 48.35)"),
    get d30() { return this.d20.lighten(TERRA.PRIMARY_SPREAD); },
    get d40() { return this.d30.lighten(TERRA.PRIMARY_SPREAD); },
    // ... mids, lights
};

const palette = createPaletteNext(primaries, {
    red: colordx("oklch(0.568 0.15 29.52)"),
    // ... rest
}, { darkenBy: TERRA.PALETTE_DARKEN });
```

This gives you the "why" without the "what's hidden."

