import type { ThemePaletteColorsNext, ThemePrimaryColorsNext } from "../../types/theme-next.ts";
import type { Colordx } from "@colordx";

/** The 6 color anchors that define a theme's palette identity. */
type PaletteAnchors = Pick<
    ThemePaletteColorsNext<Colordx>,
    "red" | "green" | "yellow" | "blue" | "magenta" | "cyan"
>;

interface CreatePaletteNextConfig {
    /** Override specific derived colors. Receives the full default palette so
     *  you can base overrides on computed values. */
    overrides?: (defaults: ThemePaletteColorsNext) => Partial<ThemePaletteColorsNext>;
    /** Tweak the derivation formulas. */
    options?: {
        /** darken factor for auto-deriving dark* variants (default 0.1) */
        darken?: number;
    };
}

export default function (
    primaries: ThemePrimaryColorsNext,
    anchors: PaletteAnchors,
    config?: CreatePaletteNextConfig,
): ThemePaletteColorsNext {
    const darkenBy = config?.options?.darken ?? 0.1;

    const defaults: ThemePaletteColorsNext = {
        ...anchors,

        darkRed: anchors.red.darken(darkenBy),
        darkGreen: anchors.green.darken(darkenBy),
        darkYellow: anchors.yellow.darken(darkenBy),
        darkBlue: anchors.blue.darken(darkenBy),
        darkMagenta: anchors.magenta.darken(darkenBy),
