    from: number;
    to: number;
    chroma: number;
    hue: number;
}

export interface DarksConfig extends RangeConfig {
    overrides?: (gen: Darks) => Partial<Darks>;
}

export interface MidsConfig extends RangeConfig {
    overrides?: (gen: Mids) => Partial<Mids>;
}

export interface LightsConfig extends RangeConfig {
    overrides?: (gen: Lights) => Partial<Lights>;
}

export interface CreatePrimaryScaleConfig {
    darks: DarksConfig;
    mids: MidsConfig;
    lights: LightsConfig;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function genOklch(luma: number, chroma: number, hue: number): Colordx {
    return new Colordx(`oklch(${luma.toFixed(3)} ${chroma.toFixed(3)} ${hue.toFixed(2)})`);
}

function generateRange<T extends Record<string, Colordx>>(
    prefix: string,
    from: number,
    to: number,
    chroma: number,
    hue: number,
    overrides?: (gen: T) => Partial<T>,
): T {
    const step = (to - from) / 3;
    const suffixes = ["10", "20", "30", "40"] as const;

    const generated = Object.fromEntries(
        suffixes.map((suffix, i) => {
            const luma = from + step * i;
            return [`${prefix}${suffix}`, genOklch(luma, chroma, hue)];
        }),
    ) as T;

    const ov = overrides?.(generated) ?? {};
    return { ...generated, ...ov };
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

/**
 * Build a 12-stop primary color scale from luma ranges.
 *
 * Each range (darks / mids / lights) declares `from` and `to` luma values
 * with shared `chroma` and `hue`. The function generates 4 equally-spaced
 * oklch values per range, then applies range-scoped overrides.
 */
export function createPrimaryScale(config: CreatePrimaryScaleConfig): ThemePrimaryColorsNext {
    const darks = generateRange<Darks>(
        "d",
        config.darks.from,
        config.darks.to,
        config.darks.chroma,
        config.darks.hue,
        config.darks.overrides,
    );

    const mids = generateRange<Mids>(
        "m",
        config.mids.from,
        config.mids.to,
        config.mids.chroma,
        config.mids.hue,
        config.mids.overrides,
    );

    const lights = generateRange<Lights>(
        "l",
        config.lights.from,
        config.lights.to,
        config.lights.chroma,
        config.lights.hue,
        config.lights.overrides,
    );

    return { ...darks, ...mids, ...lights };
}

import { assertEquals } from "@std/assert";
import { Colordx } from "@colordx";
import { createPaletteNext } from "./create-palette.ts";
import type { ThemePrimaryColorsNext } from "../types/theme-next.ts";

function mockPrimaries(overrides?: Partial<ThemePrimaryColorsNext>): ThemePrimaryColorsNext {
    return {
        d10: new Colordx("oklch(0.2 0.04 50)"),
        d20: new Colordx("oklch(0.3 0.04 50)"),
        d30: new Colordx("oklch(0.35 0.04 50)"),
        d40: new Colordx("oklch(0.44 0.04 50)"),
        m10: new Colordx("oklch(0.48 0.06 50)"),
        m20: new Colordx("oklch(0.57 0.06 50)"),
        m30: new Colordx("oklch(0.66 0.06 50)"),
        m40: new Colordx("oklch(0.74 0.06 50)"),
        l10: new Colordx("oklch(0.83 0.05 55)"),
        l20: new Colordx("oklch(0.87 0.05 55)"),
        l30: new Colordx("oklch(0.91 0.05 55)"),
        l40: new Colordx("oklch(0.94 0.05 55)"),
        ...overrides,
    };
}

Deno.test("createPaletteNext — derives dark* variants with default factor", () => {
    const primaries = mockPrimaries();
    const palette = createPaletteNext(primaries, {
        red: new Colordx("oklch(0.568 0.15 29.52)"),
        green: new Colordx("oklch(0.569 0.061 127.36)"),
        yellow: new Colordx("oklch(0.656 0.16 54.87)"),
        blue: new Colordx("oklch(0.57 0.061 49.91)"),
        magenta: new Colordx("oklch(0.57 0.085 40.86)"),
        cyan: new Colordx("oklch(0.569 0.06 175)"),
    });

    // Light anchors passed through
    assertEquals(palette.red.toHex(), new Colordx("oklch(0.568 0.15 29.52)").toHex());
    assertEquals(palette.green.toHex(), new Colordx("oklch(0.569 0.061 127.36)").toHex());

    // Dark variants derived via darken(0.1)
    assertEquals(palette.darkRed.toHex(), new Colordx("oklch(0.568 0.15 29.52)").darken(0.1).toHex());
    assertEquals(palette.darkGreen.toHex(), new Colordx("oklch(0.569 0.061 127.36)").darken(0.1).toHex());
    assertEquals(palette.darkYellow.toHex(), new Colordx("oklch(0.656 0.16 54.87)").darken(0.1).toHex());
    assertEquals(palette.darkBlue.toHex(), new Colordx("oklch(0.57 0.061 49.91)").darken(0.1).toHex());
    assertEquals(palette.darkMagenta.toHex(), new Colordx("oklch(0.57 0.085 40.86)").darken(0.1).toHex());
    assertEquals(palette.darkCyan.toHex(), new Colordx("oklch(0.569 0.06 175)").darken(0.1).toHex());
});

Deno.test("createPaletteNext — derives primaries-based entries from primaries", () => {
    const primaries = mockPrimaries();
    const palette = createPaletteNext(primaries, {
        red: new Colordx("oklch(0.568 0.15 29.52)"),
        green: new Colordx("oklch(0.569 0.061 127.36)"),
        yellow: new Colordx("oklch(0.656 0.16 54.87)"),
        blue: new Colordx("oklch(0.57 0.061 49.91)"),
        magenta: new Colordx("oklch(0.57 0.085 40.86)"),
        cyan: new Colordx("oklch(0.569 0.06 175)"),
    });

    assertEquals(palette.black.toHex(), primaries.d40.toHex());
    assertEquals(palette.gray.toHex(), primaries.m10.toHex());
    assertEquals(palette.lightGray.toHex(), primaries.l10.toHex());
    assertEquals(palette.white.toHex(), primaries.l30.toHex());
});

Deno.test("createPaletteNext — custom darken factor", () => {
    const primaries = mockPrimaries();
    const palette = createPaletteNext(primaries, {
        red: new Colordx("oklch(0.568 0.15 29.52)"),
        green: new Colordx("oklch(0.569 0.061 127.36)"),
        yellow: new Colordx("oklch(0.656 0.16 54.87)"),
        blue: new Colordx("oklch(0.57 0.061 49.91)"),
        magenta: new Colordx("oklch(0.57 0.085 40.86)"),
        cyan: new Colordx("oklch(0.569 0.06 175)"),
    }, {
        options: { darken: 0.2 },
    });

    assertEquals(palette.darkRed.toHex(), new Colordx("oklch(0.568 0.15 29.52)").darken(0.2).toHex());
    assertEquals(palette.darkBlue.toHex(), new Colordx("oklch(0.57 0.061 49.91)").darken(0.2).toHex());
});

Deno.test("createPaletteNext — overrides function replaces derived values", () => {
    const primaries = mockPrimaries();
    const customYellow = new Colordx("oklch(0.656 0.16 34.94)");

    const palette = createPaletteNext(primaries, {
        red: new Colordx("oklch(0.568 0.15 29.52)"),
        green: new Colordx("oklch(0.569 0.061 127.36)"),
        yellow: new Colordx("oklch(0.656 0.16 54.87)"),
        blue: new Colordx("oklch(0.57 0.061 49.91)"),
        magenta: new Colordx("oklch(0.57 0.085 40.86)"),
        cyan: new Colordx("oklch(0.569 0.06 175)"),
    }, {
        overrides: (d) => ({
            darkYellow: customYellow,
        }),
    });

    assertEquals(palette.darkYellow.toHex(), customYellow.toHex());
    // Other darks still use the default derivation
    assertEquals(palette.darkRed.toHex(), new Colordx("oklch(0.568 0.15 29.52)").darken(0.1).toHex());
});

Deno.test("createPaletteNext — overrides function receives defaults", () => {
    const primaries = mockPrimaries();
    let received: unknown;

    createPaletteNext(primaries, {
        red: new Colordx("oklch(0.568 0.15 29.52)"),
        green: new Colordx("oklch(0.569 0.061 127.36)"),
        yellow: new Colordx("oklch(0.656 0.16 54.87)"),
        blue: new Colordx("oklch(0.57 0.061 49.91)"),
        magenta: new Colordx("oklch(0.57 0.085 40.86)"),
        cyan: new Colordx("oklch(0.569 0.06 175)"),
    }, {
        overrides: (d) => {
            received = d;
            return {};
        },
    });

    const defaults = received as Record<string, unknown>;
    assertEquals(defaults.red instanceof Colordx, true);
    assertEquals(defaults.darkRed instanceof Colordx, true);
    assertEquals(defaults.black instanceof Colordx, true);
    assertEquals(defaults.darkYellow instanceof Colordx, true);
});

Deno.test("createPaletteNext — returns all 16 palette entries", () => {
    const primaries = mockPrimaries();
    const palette = createPaletteNext(primaries, {
        red: new Colordx("oklch(0.568 0.15 29.52)"),
        green: new Colordx("oklch(0.569 0.061 127.36)"),
        yellow: new Colordx("oklch(0.656 0.16 54.87)"),
        blue: new Colordx("oklch(0.57 0.061 49.91)"),
        magenta: new Colordx("oklch(0.57 0.085 40.86)"),
        cyan: new Colordx("oklch(0.569 0.06 175)"),
    });

    const expectedKeys = [
        "black", "gray", "lightGray", "white",
        "red", "darkRed", "green", "darkGreen",
        "yellow", "darkYellow", "blue", "darkBlue",
        "magenta", "darkMagenta", "cyan", "darkCyan",
    ];

    for (const key of expectedKeys) {
        assertEquals(palette[key as keyof typeof palette] instanceof Colordx, true, `${key} should be a Colordx`);
    }
});

import { assertEquals } from "@std/assert";
import { Colordx } from "@colordx";
import { createPrimaryScale } from "./create-primary-scale.ts";

Deno.test("createPrimaryScale — generates equally-spaced luma per range", () => {
    const scale = createPrimaryScale({
        darks: { from: 0.2, to: 0.44, chroma: 0.05, hue: 49 },
        mids: { from: 0.48, to: 0.74, chroma: 0.075, hue: 49 },
        lights: { from: 0.83, to: 0.94, chroma: 0.05, hue: 60 },
    });

    // Dark range: 4 equal luma steps
    assertEquals(scale.d10.toOklch().l, 0.2);
    assertEquals(scale.d20.toOklch().l, 0.28);
    assertEquals(scale.d30.toOklch().l, 0.36);
    assertEquals(scale.d40.toOklch().l, 0.44);

    // All dark values share chroma and hue
    assertEquals(scale.d20.toOklch().c, 0.05);
    assertEquals(scale.d20.toOklch().h, 49);
});

Deno.test("createPrimaryScale — mid range is generated correctly", () => {
    const scale = createPrimaryScale({
        darks: { from: 0.2, to: 0.44, chroma: 0.05, hue: 49 },
        mids: { from: 0.48, to: 0.74, chroma: 0.075, hue: 49 },
        lights: { from: 0.83, to: 0.94, chroma: 0.05, hue: 60 },
    });

    assertEquals(scale.m10.toOklch().l, 0.48);
    assertEquals(scale.m20.toOklch().l, 0.5667);
    assertEquals(scale.m30.toOklch().l, 0.6533);
    assertEquals(scale.m40.toOklch().l, 0.74);

    assertEquals(scale.m20.toOklch().c, 0.075);
    assertEquals(scale.m20.toOklch().h, 49);
});

Deno.test("createPrimaryScale — light range is generated correctly", () => {
    const scale = createPrimaryScale({
        darks: { from: 0.2, to: 0.44, chroma: 0.05, hue: 49 },
        mids: { from: 0.48, to: 0.74, chroma: 0.075, hue: 49 },
        lights: { from: 0.83, to: 0.94, chroma: 0.05, hue: 60 },
    });

    assertEquals(scale.l10.toOklch().l, 0.83);
    assertEquals(scale.l20.toOklch().l, 0.8667);
    assertEquals(scale.l30.toOklch().l, 0.9033);
    assertEquals(scale.l40.toOklch().l, 0.94);

    assertEquals(scale.l20.toOklch().c, 0.05);
    assertEquals(scale.l20.toOklch().h, 60);
});

Deno.test("createPrimaryScale — darks overrides replace specific values", () => {
    const customD20 = new Colordx("oklch(0.301 0.049 48.35)");

    const scale = createPrimaryScale({
        darks: {
            from: 0.2, to: 0.44, chroma: 0.05, hue: 49,
            overrides: (gen) => ({
                d20: customD20,
            }),
        },
        mids: { from: 0.48, to: 0.74, chroma: 0.075, hue: 49 },
        lights: { from: 0.83, to: 0.94, chroma: 0.05, hue: 60 },
    });

    // Override applied
    assertEquals(scale.d20.toOklch().l, customD20.toOklch().l);
    assertEquals(scale.d20.toOklch().c, customD20.toOklch().c);

    // Other positions unchanged
    assertEquals(scale.d10.toOklch().l, 0.2);
    assertEquals(scale.d30.toOklch().l, 0.36);
});

Deno.test("createPrimaryScale — mids overrides can reference generated values", () => {
    const scale = createPrimaryScale({
        darks: { from: 0.2, to: 0.44, chroma: 0.05, hue: 49 },
        mids: {
            from: 0.48, to: 0.74, chroma: 0.075, hue: 49,
            overrides: (gen) => ({
                m20: gen.m20.withChroma(0.074),
            }),
        },
        lights: { from: 0.83, to: 0.94, chroma: 0.05, hue: 60 },
