    assertEquals(scale.d40.toOklch().l, 0.2);
});

Deno.test("createPrimaryScale — returns all 12 primary scale entries", () => {
    const scale = createPrimaryScale({
        darks: { from: 0.2, to: 0.44, chroma: 0.05, hue: 49 },
        mids: { from: 0.48, to: 0.74, chroma: 0.075, hue: 49 },
        lights: { from: 0.83, to: 0.94, chroma: 0.05, hue: 60 },
    });

    const expectedKeys = [
        "d10", "d20", "d30", "d40",
        "m10", "m20", "m30", "m40",
        "l10", "l20", "l30", "l40",
    ];

    for (const key of expectedKeys) {
        assertEquals(
