import { assertEquals } from "@std/assert";
import { Colordx } from "@colordx";
import { createPrimaryScale } from "./create-primary-scale.ts";

function roundLuma(c: Colordx): number {
    return Math.round(c.toOklch().l * 1000) / 1000;
}

function roundChroma(c: Colordx): number {
    return Math.round(c.toOklch().c * 1000) / 1000;
}

function roundHue(c: Colordx): number {
    return Math.round(c.toOklch().h * 100) / 100;
}

Deno.test("createPrimaryScale — generates equally-spaced luma per range", () => {
    const scale = createPrimaryScale({
        darks: { from: 0.2, to: 0.44, chroma: 0.05, hue: 49 },
        mids: { from: 0.48, to: 0.74, chroma: 0.075, hue: 49 },
        lights: { from: 0.83, to: 0.94, chroma: 0.05, hue: 60 },
    });

    // Dark range: 4 equal luma steps (rounded to 3 decimals from toFixed)
    assertEquals(roundLuma(scale.d10), 0.2);
    assertEquals(roundLuma(scale.d20), 0.28);
    assertEquals(roundLuma(scale.d30), 0.36);
    assertEquals(roundLuma(scale.d40), 0.44);

    // All dark values share chroma and hue
    assertEquals(roundChroma(scale.d20), 0.05);
    assertEquals(roundHue(scale.d20), 49);
});

Deno.test("createPrimaryScale — mid range is generated correctly", () => {
    const scale = createPrimaryScale({
        darks: { from: 0.2, to: 0.44, chroma: 0.05, hue: 49 },
        mids: { from: 0.48, to: 0.74, chroma: 0.075, hue: 49 },
        lights: { from: 0.83, to: 0.94, chroma: 0.05, hue: 60 },
    });

    assertEquals(roundLuma(scale.m10), 0.48);
    assertEquals(roundLuma(scale.m20), 0.567);
    assertEquals(roundLuma(scale.m30), 0.653);
    assertEquals(roundLuma(scale.m40), 0.74);

    assertEquals(roundChroma(scale.m20), 0.075);
    assertEquals(roundHue(scale.m20), 49);
});

Deno.test("createPrimaryScale — light range is generated correctly", () => {
    const scale = createPrimaryScale({
        darks: { from: 0.2, to: 0.44, chroma: 0.05, hue: 49 },
        mids: { from: 0.48, to: 0.74, chroma: 0.075, hue: 49 },
        lights: { from: 0.83, to: 0.94, chroma: 0.05, hue: 60 },
    });

    assertEquals(roundLuma(scale.l10), 0.83);
    assertEquals(roundLuma(scale.l20), 0.867);
    assertEquals(roundLuma(scale.l30), 0.903);
    assertEquals(roundLuma(scale.l40), 0.94);

    assertEquals(roundChroma(scale.l20), 0.05);
    assertEquals(roundHue(scale.l20), 60);
});

Deno.test("createPrimaryScale — darks overrides replace specific values", () => {
    const customD20 = new Colordx("oklch(0.301 0.049 48.35)");

    const scale = createPrimaryScale({
        darks: {
            from: 0.2, to: 0.44, chroma: 0.05, hue: 49,
            overrides: () => ({
                d20: customD20,
            }),
        },
        mids: { from: 0.48, to: 0.74, chroma: 0.075, hue: 49 },
        lights: { from: 0.83, to: 0.94, chroma: 0.05, hue: 60 },
    });

    // Override applied
    assertEquals(roundLuma(scale.d20), 0.301);
    assertEquals(roundChroma(scale.d20), 0.049);

    // Other positions unchanged
    assertEquals(roundLuma(scale.d10), 0.2);
    assertEquals(roundLuma(scale.d30), 0.36);
});

Deno.test("createPrimaryScale — mids overrides can reference generated values", () => {
    const scale = createPrimaryScale({
        darks: { from: 0.2, to: 0.44, chroma: 0.05, hue: 49 },
        mids: {
            from: 0.48, to: 0.74, chroma: 0.075, hue: 49,
            overrides: () => ({
                m20: new Colordx("oklch(0.567 0.074 49)"),
            }),
        },
        lights: { from: 0.83, to: 0.94, chroma: 0.05, hue: 60 },
    });

    // m20 should have the overridden chroma, luma should match the generated luma
    assertEquals(roundChroma(scale.m20), 0.074);
    assertEquals(roundLuma(scale.m20), 0.567);
});

Deno.test("createPrimaryScale — lights overrides replace specific values", () => {
    const customL20 = new Colordx("oklch(0.872 0.048 58.95)");

    const scale = createPrimaryScale({
        darks: { from: 0.2, to: 0.44, chroma: 0.05, hue: 49 },
        mids: { from: 0.48, to: 0.74, chroma: 0.075, hue: 49 },
        lights: {
            from: 0.83, to: 0.94, chroma: 0.05, hue: 60,
            overrides: () => ({
                l20: customL20,
            }),
        },
    });

    assertEquals(roundLuma(scale.l20), 0.872);
    assertEquals(roundChroma(scale.l20), 0.048);
    assertEquals(roundLuma(scale.l10), 0.83); // unchanged
});

Deno.test("createPrimaryScale — handles from > to (reversed luma range)", () => {
    const scale = createPrimaryScale({
        darks: { from: 0.44, to: 0.2, chroma: 0.05, hue: 49 },
        mids: { from: 0.48, to: 0.74, chroma: 0.075, hue: 49 },
        lights: { from: 0.83, to: 0.94, chroma: 0.05, hue: 60 },
    });

    // Values should be in descending order
    assertEquals(roundLuma(scale.d10), 0.44);
    assertEquals(roundLuma(scale.d40), 0.2);
});

Deno.test("createPrimaryScale — returns all 12 primary scale entries", () => {
    const scale = createPrimaryScale({
        darks: { from: 0.2, to: 0.44, chroma: 0.05, hue: 49 },
        mids: { from: 0.48, to: 0.74, chroma: 0.075, hue: 49 },
        lights: { from: 0.83, to: 0.94, chroma: 0.05, hue: 60 },
    });

    const expectedKeys = [
        "d10", "d20", "d30", "d40",
        "m10", "m20", "m30", "m40",
        "l10", "l20", "l30", "l40",
    ];

    for (const key of expectedKeys) {
        assertEquals(
            scale[key as keyof typeof scale] instanceof Colordx,
            true,
            `${key} should be a Colordx`,
        );
    }
});

